using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using OpenAI;

// ── Bootstrap ────────────────────────────────────────────────────────
var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in config or the OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(cb => cb
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

using var host = builder.Build();

// ── Tools ────────────────────────────────────────────────────────────
var notebook = new Notebook();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            Console.WriteLine($"  🔍  Searching: \"{query}\"");
            return WebSearchSimulator.Search(query);
        },
        "web_search",
        "Searches the web for information on a topic and returns relevant results."),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content to save")] string content) =>
        {
            Console.WriteLine($"  📝  Saving note: \"{title}\"");
            notebook.AddNote(title, content);
            return $"Note \"{title}\" saved successfully.";
        },
        "save_note",
        "Saves a research note with a title and content for later reference."),

    AIFunctionFactory.Create(
        () =>
        {
            Console.WriteLine("  📖  Reading all notes");
            return notebook.GetAllNotes();
        },
        "read_notes",
        "Returns all previously saved research notes."),
};

// ── Agent setup ──────────────────────────────────────────────────────
var chatClient = host.Services.GetRequiredService<IChatClient>();

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. When the user gives you a topic:
        1. Search the web for information (use multiple varied queries to get broad coverage).
        2. Save important findings as notes using the save_note tool.
        3. After gathering enough information, read your notes and produce a
           well-structured summary with key findings and sources.
        Be thorough but concise. Use at least 3 different search queries.
        """,
};

// ── Run ──────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║         🔬  Research Agent  🔬          ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");

while (true)
{
    Console.Write("\n📌 Topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and summarize your findings: {topic}"),
    };

    var options = new AgentInvokeOptions
    {
        MaximumIterations = 15,
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    };

    Console.WriteLine($"\n🔬 Researching \"{topic}\"...\n");

    string? finalResponse = null;
    await foreach (var message in agent.InvokeStreamingAsync(history, options))
    {
        if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
        {
            finalResponse = message.Text;
        }
    }

    Console.WriteLine("\n═══════════════ SUMMARY ═══════════════\n");
    Console.WriteLine(finalResponse ?? "(No summary produced)");
    Console.WriteLine("\n═══════════════════════════════════════\n");
}

Console.WriteLine("Goodbye! 👋");

// ── Supporting types ─────────────────────────────────────────────────

/// <summary>Simple in-memory notebook for the agent's research notes.</summary>
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public void AddNote(string title, string content) =>
        _notes.Add((title, content));

    public string GetAllNotes() =>
        _notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n\n", _notes.Select((n, i) =>
                $"[Note {i + 1}] {n.Title}\n{n.Content}"));

    public void Clear() => _notes.Clear();
}

/// <summary>
/// Simulates web search results so the app works without external APIs.
/// Replace with a real search API (Bing, Google, Brave) for production use.
/// </summary>
static class WebSearchSimulator
{
    public static string Search(string query)
    {
        var q = query.ToLowerInvariant();

        // Return plausible, topic-aware stub results.
        if (q.Contains("quantum computing"))
            return JsonSerializer.Serialize(new[]
            {
                new { title = "Quantum Computing Overview – Nature", snippet = "Quantum computers use qubits that leverage superposition and entanglement to perform computations exponentially faster for certain problems like factoring, simulation, and optimization." },
                new { title = "IBM Quantum Roadmap 2025", snippet = "IBM plans to deliver 100,000-qubit systems by 2033. Current systems exceed 1,000 qubits with error-mitigation techniques." },
                new { title = "Google Willow chip – arXiv 2024", snippet = "Google's Willow chip demonstrated below-threshold quantum error correction for the first time, a major milestone toward fault-tolerant quantum computing." },
            });

        if (q.Contains("climate") || q.Contains("global warming"))
            return JsonSerializer.Serialize(new[]
            {
                new { title = "IPCC AR6 Synthesis Report", snippet = "Global surface temperature has increased by 1.1°C since pre-industrial times. Limiting warming to 1.5°C requires CO₂ emissions to reach net zero by 2050." },
                new { title = "NASA Climate Change Evidence", snippet = "Arctic sea ice is declining at 13% per decade. Sea levels have risen 20 cm since 1900 and the rate is accelerating." },
                new { title = "Renewable Energy Transition – IEA 2024", snippet = "Renewables accounted for 30% of global electricity in 2023. Solar capacity additions exceeded all other sources combined." },
            });

        // Generic fallback
        return JsonSerializer.Serialize(new[]
        {
            new { title = $"Wikipedia: {query}", snippet = $"A comprehensive overview of {query} covering history, current developments, and future outlook." },
            new { title = $"Recent advances in {query} – ScienceDirect", snippet = $"Recent research on {query} has shown significant progress in multiple areas including practical applications and theoretical foundations." },
            new { title = $"{query} explained – MIT Technology Review", snippet = $"An accessible explanation of {query}, its implications for industry and society, and expert opinions on where the field is headed." },
        });
    }
}

