 using System.ComponentModel;
 using System.Text.Json;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using Microsoft.Extensions.DependencyInjection;
 using Microsoft.Extensions.Hosting;
 using OpenAI;

 // ── Bootstrap ────────────────────────────────────────────────────────
 var builder = Host.CreateApplicationBuilder(args);

 var apiKey = builder.Configuration["AI:ApiKey"]
     ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set AI:ApiKey in config or the OPENAI_API_KEY environment variable.");

 const string modelId = "gpt-4o-mini-2024-07-18";

 builder.Services.AddChatClient(_ =>
     new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient());

 using var host = builder.Build();

 // ── Tools ────────────────────────────────────────────────────────────
 var notebook = new Notebook();

 var tools = new AIFunction[]
 {
     AIFunctionFactory.Create(
         ([Description("The search query to look up on the web")] string query) =>
         {
             Console.WriteLine($"  🔍  Searching: \"{query}\"");
             return WebSearchSimulator.Search(query);
         },
         "web_search",
         "Searches the web for information on a topic and returns relevant results."),

     AIFunctionFactory.Create(
         ([Description("Title for the note")] string title,
          [Description("Content to save")] string content) =>
         {
             Console.WriteLine($"  📝  Saving note: \"{title}\"");
             notebook.AddNote(title, content);
             return $"Note \"{title}\" saved successfully.";
         },
         "save_note",
         "Saves a research note with a title and content for later reference."),

     AIFunctionFactory.Create(
         () =>
         {
             Console.WriteLine("  📖  Reading all notes");
             return notebook.GetAllNotes();
         },
         "read_notes",
         "Returns all previously saved research notes."),
 };

 // ── Agent setup ──────────────────────────────────────────────────────
 var chatClient = host.Services.GetRequiredService<IChatClient>();

 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. When the user gives you a topic:
         1. Search the web for information (use multiple varied queries to get broad coverage).
         2. Save important findings as notes using the save_note tool.
         3. After gathering enough information, read your notes and produce a
            well-structured summary with key findings and sources.
         Be thorough but concise. Use at least 3 different search queries.
         """,
     name: "ResearchAgent",
     description: "An agent that researches topics by searching the web and taking notes.",
     tools: tools);

 // ── Run ──────────────────────────────────────────────────────────────
 Console.WriteLine("╔══════════════════════════════════════════╗");
 Console.WriteLine("║         🔬  Research Agent  🔬          ║");
 Console.WriteLine("╠══════════════════════════════════════════╣");
 Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
 Console.WriteLine("╚══════════════════════════════════════════╝");

 while (true)
 {
     Console.Write("\n📌 Topic: ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     notebook.Clear();

     var runOptions = new ChatClientAgentRunOptions(new ChatOptions
     {
         Temperature = 0f,
         MaxOutputTokens = 2048,
     });

     Console.WriteLine($"\n🔬 Researching \"{topic}\"...\n");

     var session = await agent.CreateSessionAsync();

     string? finalResponse = null;
     await foreach (var update in agent.RunStreamingAsync(
         $"Research the following topic and summarize your findings: {topic}",
         session,
         runOptions))
     {
         if (!string.IsNullOrWhiteSpace(update.Text))
         {
             finalResponse = update.Text;
         }
     }

     Console.WriteLine("\n═══════════════ SUMMARY ═══════════════\n");
     Console.WriteLine(finalResponse ?? "(No summary produced)");
     Console.WriteLine("\n═══════════════════════════════════════\n");
 }

 Console.WriteLine("Goodbye! 👋");

 // ── Supporting types ─────────────────────────────────────────────────

 /// <summary>Simple in-memory notebook for the agent's research notes.</summary>
 sealed class Notebook
 {
     private readonly List<(string Title, string Content)> _notes = [];

     public void AddNote(string title, string content) =>
         _notes.Add((title, content));

     public string GetAllNotes() =>
         _notes.Count == 0
             ? "No notes saved yet."
             : string.Join("\n\n", _notes.Select((n, i) =>
                 $"[Note {i + 1}] {n.Title}\n{n.Content}"));

     public void Clear() => _notes.Clear();
 }

 /// <summary>
 /// Simulates web search results so the app works without external APIs.
 /// Replace with a real search API (Bing, Google, Brave) for production use.
 /// </summary>
 static class WebSearchSimulator
 {
     public static string Search(string query)
     {
         var q = query.ToLowerInvariant();

         if (q.Contains("quantum computing"))
             return JsonSerializer.Serialize(new[]
             {
