             });

         if (q.Contains("climate") || q.Contains("global warming"))
             return JsonSerializer.Serialize(new[]
             {
                 new { title = "IPCC AR6 Synthesis Report", snippet = "Global surface temperature has increased by 1.1°C since pre-industrial times. Limiting warming to 1.5°C requires CO₂ emissions to reach net zero by 2050." },
                 new { title = "NASA Climate Change Evidence", snippet = "Arctic sea ice is declining at 13% per decade. Sea levels have risen 20 cm since 1900 and the rate is accelerating." },
                 new { title = "Renewable Energy Transition – IEA 2024", snippet = "Renewables accounted for 30% of global electricity in 2023. Solar capacity additions exceeded all other sources combined." },
             });

         return JsonSerializer.Serialize(new[]
         {
             new { title = $"Wikipedia: {query}", snippet = $"A comprehensive overview of {query} covering history, current developments, and future outlook." },
             new { title = $"Recent advances in {query} – ScienceDirect", snippet = $"Recent research on {query} has shown significant progress in multiple areas including practical applications and theoretical foundations." },
             new { title = $"{query} explained – MIT Technology Review", snippet = $"An accessible explanation of {query}, its implications for industry and society, and expert opinions on where the field is headed." },
